import sailpoint.object.Identity;

//Provide any Identity in the referenced workgroup with the relevant role.

String workgroupName = "Application Notifications Workgroup";

Identity workgroup = context.getObjectByName(Identity.class, workgroupName);

if (workgroup != null && workgroup.isWorkgroup()) {

   if (identity.isInWorkGroup(workgroup)) {

     return true;

   } 

}

return false;
